     1→/*
     2→ * sinf() test harness — prints (input_hex, output_hex) pairs.
     3→ *
     4→ * Build two versions:
     5→ *   1. Linked with optimized Andes assembly sinf  (test_sinf_opt.elf)
     6→ *   2. Linked with toolchain's default sinf        (test_sinf_ref.elf)
     7→ * Run both, diff the output to find discrepancies.
     8→ */
     9→
    10→#include <math.h>
    11→#include <stdint.h>
    12→#include <stdio.h>
    13→#include <float.h>
    14→
    15→static inline uint32_t f2u(float f)
    16→{
    17→    union { float f; uint32_t u; } x;
    18→    x.f = f;
    19→    return x.u;
    20→}
    21→
    22→static inline float u2f(uint32_t u)
    23→{
    24→    union { float f; uint32_t u; } x;
    25→    x.u = u;
    26→    return x.f;
    27→}
    28→
    29→static void emit(float x)
    30→{
    31→    float r = sinf(x);
    32→    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
    33→}
    34→
    35→static void emit_u(uint32_t bits)
    36→{
    37→    emit(u2f(bits));
    38→}
    39→
    40→/* ------------------------------------------------------------------ */
    41→/* Test points                                                         */
    42→/* ------------------------------------------------------------------ */
    43→
    44→/* 1. Special values */
    45→static void test_special(void)
    46→{
    47→    /* Zeros */
    48→    emit(0.0f);
    49→    emit(-0.0f);
    50→
    51→    /* NaN */
    52→    emit_u(0x7fc00000u); /* qNaN */
    53→    emit_u(0x7f800001u); /* sNaN */
    54→    emit_u(0xffc00000u); /* -NaN */
    55→
    56→    /* Infinity */
    57→    emit_u(0x7f800000u); /* +Inf */
    58→    emit_u(0xff800000u); /* -Inf */
    59→}
    60→
    61→/* 2. Tiny values: sin(x) ~ x */
    62→static void test_tiny(void)
    63→{
    64→    emit_u(0x00000001u); /* min denorm */
    65→    emit_u(0x80000001u);
    66→    emit_u(0x00400000u); /* mid denorm */
    67→    emit_u(0x80400000u);
    68→    emit_u(0x007fffffu); /* max denorm */
    69→    emit_u(0x807fffffu);
    70→    emit(FLT_MIN);
    71→    emit(-FLT_MIN);
    72→    emit(1.0e-20f);
    73→    emit(-1.0e-20f);
    74→    emit(1.0e-10f);
    75→    emit(-1.0e-10f);
    76→}
    77→
    78→/* 3. Known mathematical values */
    79→static void test_known(void)
    80→{
    81→    float pi   = 3.14159265358979323846f;
    82→    float pi_2 = 1.57079632679489661923f;
    83→    float pi_3 = 1.04719755119659774615f;
    84→    float pi_4 = 0.78539816339744830962f;
    85→    float pi_6 = 0.52359877559829887308f;
    86→
    87→    emit(pi_6);
    88→    emit(pi_4);
    89→    emit(pi_3);
    90→    emit(pi_2);
    91→    emit(pi);
    92→    emit(2.0f * pi);
    93→    emit(-pi_6);
    94→    emit(-pi_4);
    95→    emit(-pi_2);
    96→    emit(-pi);
    97→    emit(3.0f * pi_2);
    98→    emit(pi_2 + 0.001f);
    99→    emit(pi + 0.001f);
   100→    emit(pi - 0.001f);
   101→}
   102→
   103→/* 4. Large arguments */
   104→static void test_large(void)
   105→{
   106→    float vals[] = {
   107→        10.0f, 100.0f, 1000.0f, 100000.0f, 1000000.0f,
   108→        -10.0f, -1000.0f,
   109→        3.14159265f * 100.0f,
   110→        3.14159265f * 1000.0f,
   111→        1.0e10f, 1.0e20f,
   112→        -1.0e10f, -1.0e20f,
   113→        FLT_MAX, -FLT_MAX,
   114→    };
   115→    int n = sizeof(vals) / sizeof(vals[0]);
   116→    for (int i = 0; i < n; i++)
   117→        emit(vals[i]);
   118→}
   119→
   120→/* 5. Quadrant transitions */
   121→static void test_quadrant(void)
   122→{
   123→    float pi_2 = 1.5707963267948966f;
   124→    float offsets[] = { -1e-5f, 0.0f, 1e-5f };
   125→    int noff = sizeof(offsets) / sizeof(offsets[0]);
   126→
   127→    for (int k = 1; k <= 8; k++) {
   128→        float boundary = (float)((double)k * (double)pi_2);
   129→        for (int j = 0; j < noff; j++)
   130→            emit(boundary + offsets[j]);
   131→    }
   132→}
   133→
   134→/* 6. Worst-case argument reduction */
   135→static void test_hard(void)
   136→{
   137→    float cases[] = {
   138→        u2f(0x40490fdbu), /* pi as float */
   139→        u2f(0x40c90fdbu), /* 2*pi as float */
   140→        u2f(0x4096cbe4u), /* 3*pi/2 */
   141→        4.0f, 16.0f, 64.0f, 256.0f,
   142→    };
   143→    int n = sizeof(cases) / sizeof(cases[0]);
   144→    for (int i = 0; i < n; i++) {
   145→        emit(cases[i]);
   146→        emit(-cases[i]);
   147→    }
   148→}
   149→
   150→/* 7. Sweep [0, 4*pi] and [-4*pi, 0] in 200 steps each */
   151→static void test_sweep(void)
   152→{
   153→    float hi = 4.0f * 3.14159265358979323846f;
   154→    int nsteps = 200;
   155→    float step = hi / (float)nsteps;
   156→
   157→    /* [0, 4*pi] */
   158→    for (int i = 0; i <= nsteps; i++)
   159→        emit((float)i * step);
   160→
   161→    /* [-4*pi, 0] */
   162→    for (int i = 0; i <= nsteps; i++)
   163→        emit(-hi + (float)i * step);
   164→}
   165→
   166→/* 8. Sample [0, pi/4] every 4194304 ULP (~250 cases) */
   167→static void test_exhaustive_small(void)
   168→{
   169→    uint32_t end = 0x3f490fdbu; /* pi/4 */
   170→    for (uint32_t b = 0; b <= end; b += 4194304)
   171→        emit_u(b);
   172→}
   173→
   174→/* ------------------------------------------------------------------ */
   175→
   176→int main(void)
   177→{
   178→    test_special();
   179→    test_tiny();
   180→    test_known();
   181→    test_large();
   182→    test_quadrant();
   183→    test_hard();
   184→    test_sweep();
   185→    test_exhaustive_small();
   186→    return 0;
   187→}
   188→

