     9→
    10→static inline uint64_t d2u(double d)
    11→{
    12→    union { double d; uint64_t u; } x;
    13→    x.d = d;
    14→    return x.u;
    15→}
    16→
    17→static inline double u2d(uint64_t u)
    18→{
    19→    union { double d; uint64_t u; } x;
    20→    x.u = u;
    21→    return x.d;
    22→}
    23→
    24→static void emit(double x)
    25→{
    26→    double r = sinh(x);
    27→    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
    28→}
