    35→/* Test special values */
    36→static void test_special(void)
    37→{
    38→    emit(0.0);
    39→    emit(-0.0);
    40→    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    41→    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    42→    emit_u(0xfff0000000000000ULL);  /* -Inf */
    43→}
    44→
    45→/* Test tiny values */
    46→static void test_tiny(void)
    47→{
    48→    emit(1.0e-200);
    49→    emit(-1.0e-200);
    50→    emit(DBL_MIN);
    51→    emit(-DBL_MIN);
    52→}
    53→
    54→/* Test normal range */
    55→static void test_normal(void)
    56→{
    57→    double vals[] = { 0.1, 0.5, 1.0, 2.0, 5.0, 10.0 };
    58→    int n = sizeof(vals) / sizeof(vals[0]);
    59→    for (int i = 0; i < n; i++) {
    60→        emit(vals[i]);
    61→        emit(-vals[i]);
    62→    }
    63→}
    64→
    65→/* Test large values */
    66→static void test_large(void)
    67→{
    68→    emit(100.0);
    69→    emit(-100.0);
    70→    emit(700.0);   /* near overflow */
    71→    emit(709.0);   /* overflow boundary */
    72→}
    73→
    74→int main(void)
    75→{
    76→    test_special();
    77→    test_tiny();
    78→    test_normal();
    79→    test_large();
    80→    return 0;
    81→}
