/*
 * sinh() test harness — prints (input_hex, output_hex) pairs.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static void emit(double x)
{
    double r = sinh(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* Test special values */
static void test_special(void)
{
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */
}

/* Test tiny values */
static void test_tiny(void)
{
    emit(1.0e-200);
    emit(-1.0e-200);
    emit(DBL_MIN);
    emit(-DBL_MIN);
}

/* Test normal range */
static void test_normal(void)
{
    double vals[] = { 0.1, 0.5, 1.0, 2.0, 5.0, 10.0 };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++) {
        emit(vals[i]);
        emit(-vals[i]);
    }
}

/* Test large values */
static void test_large(void)
{
    emit(100.0);
    emit(-100.0);
    emit(700.0);   /* near overflow */
    emit(709.0);   /* overflow boundary */
}

int main(void)
{
    test_special();
    test_tiny();
    test_normal();
    test_large();
    return 0;
}

